def get_input():
    n = int(input())
    graph = [[0] * n for _ in range(n)]
    for i in range(n):
        row = list(map(int, input().split()))
        for j in range(i + 1, n):
            graph[i][j] = graph[j][i] = row[j]
    return graph

def get_shortest_path(graph, n):
    dist = [[float('inf')] * n for _ in range(n)]
    for i in range(n):
        dist[i][i] = 0
        for j in range(n):
            if graph[i][j] != 0:
                dist[i][j] = graph[i][j]
    for k in range(n):
        for i in range(n):
            for j in range(n):
                dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
    return dist

def get_longest_path(graph, n):
    dist = get_shortest_path(graph, n)
    return max(max(row) for row in dist)

graph = get_input()
n = len(graph)
print(get_longest_path(graph, n))
